Using SHA1 or MD5 for password hashing is **critically insecure** and should never be used. These algorithms were designed for speed, not security - making them trivial to crack with modern hardware.

**VULNERABLE CODE**:

```javascript
const crypto = require('crypto');
const express = require('express');
const app = express();

app.use(express.json());

// DANGEROUS: Using MD5 for password hashing
function hashPasswordMD5(password) {
    return crypto.createHash('md5').update(password).digest('hex');
}

// DANGEROUS: Using SHA1 for password hashing
function hashPasswordSHA1(password) {
    return crypto.createHash('sha1').update(password).digest('hex');
}

app.post('/register', (req, res) => {
    const { username, password } = req.body;

    // Vulnerable: Fast hash without salt
    const hashedPassword = hashPasswordSHA1(password);

    // Store in database
    db.query('INSERT INTO users (username, password) VALUES (?, ?)', 
             [username, hashedPassword]);

    res.json({ message: 'User registered' });
});

app.post('/login', (req, res) => {
    const { username, password } = req.body;
    const hashedInput = hashPasswordSHA1(password);

    // Compare hashes directly
    const user = db.query('SELECT * FROM users WHERE username = ? AND password = ?',
                          [username, hashedInput]);

    if (user) {
        res.json({ message: 'Login successful' });
    } else {
        res.status(401).json({ message: 'Invalid credentials' });
    }
});
```

**Attack Demonstration**:
```bash
# GPU cracking speed on RTX 4090:
# MD5: ~164 billion hashes/second
# SHA1: ~27 billion hashes/second

# Using hashcat to crack SHA1 passwords:
hashcat -m 100 -a 0 hashes.txt rockyou.txt

# Rainbow table lookup (instant for common passwords):
# SHA1 of 'password123' = cbfdac6008f9cab4083784cbd1874f76618d2a97
```

**Why This Is Dangerous**:
- MD5/SHA1 are designed for speed, allowing billions of guesses per second
- No salt means identical passwords produce identical hashes (rainbow table attacks)
- Precomputed tables exist for common passwords, enabling instant lookups
- A single GPU can crack most passwords in minutes to hours
- These algorithms have known collision vulnerabilities

**SECURE VERSION**:

```javascript
const bcrypt = require('bcrypt');
const express = require('express');
const app = express();

app.use(express.json());

// Cost factor (2^12 = 4096 iterations)
const SALT_ROUNDS = 12;

// SECURE: Using bcrypt with automatic salt generation
async function hashPassword(password) {
    // bcrypt automatically generates a cryptographically secure salt
    // and includes it in the output hash
    return await bcrypt.hash(password, SALT_ROUNDS);
}

// SECURE: Constant-time comparison
async function verifyPassword(password, hashedPassword) {
    // bcrypt.compare is timing-safe and extracts salt from hash
    return await bcrypt.compare(password, hashedPassword);
}

app.post('/register', async (req, res) => {
    try {
        const { username, password } = req.body;

        // Validate password strength before hashing
        if (password.length < 12) {
            return res.status(400).json({ 
                message: 'Password must be at least 12 characters' 
            });
        }

        // Secure: Slow hash with embedded salt
        const hashedPassword = await hashPassword(password);

        // Store in database (hash includes salt)
        await db.query('INSERT INTO users (username, password_hash) VALUES (?, ?)', 
                       [username, hashedPassword]);

        res.json({ message: 'User registered successfully' });
    } catch (error) {
        console.error('Registration error:', error.message);
        res.status(500).json({ message: 'Registration failed' });
    }
});

app.post('/login', async (req, res) => {
    try {
        const { username, password } = req.body;

        const user = await db.query(
            'SELECT password_hash FROM users WHERE username = ?',
            [username]
        );

        if (!user) {
            // Perform dummy hash to prevent timing attacks
            await bcrypt.hash('dummy', SALT_ROUNDS);
            return res.status(401).json({ message: 'Invalid credentials' });
        }

        const isValid = await verifyPassword(password, user.password_hash);

        if (isValid) {
            res.json({ message: 'Login successful' });
        } else {
            res.status(401).json({ message: 'Invalid credentials' });
        }
    } catch (error) {
        console.error('Login error:', error.message);
        res.status(500).json({ message: 'Login failed' });
    }
});
```

**Key Security Controls**:
- **bcrypt with cost factor 12**: Each hash takes ~250ms, making brute force impractical (billions of years vs hours)
- **Automatic salt generation**: Every password gets a unique 128-bit salt, defeating rainbow tables
- **Timing-safe comparison**: bcrypt.compare prevents timing side-channel attacks
- **Salt embedded in hash**: No separate salt storage needed, simplifying implementation

Excellent questions! Argon2 is the winner of the 2015 Password Hashing Competition and offers superior protection against GPU/ASIC attacks through memory-hardness. For migrations, you need a transparent upgrade strategy that rehashes on successful login.

**PRODUCTION PATTERN**:

```javascript
const argon2 = require('argon2');
const bcrypt = require('bcrypt');
const crypto = require('crypto');
const express = require('express');
const rateLimit = require('express-rate-limit');
const winston = require('winston');

const app = express();
app.use(express.json());

// Security logging configuration
const securityLogger = winston.createLogger({
    level: 'info',
    format: winston.format.json(),
    transports: [
        new winston.transports.File({ filename: 'security-audit.log' })
    ]
});

// Rate limiting for authentication endpoints
const authLimiter = rateLimit({
    windowMs: 15 * 60 * 1000, // 15 minutes
    max: 5, // 5 attempts per window
    message: { message: 'Too many login attempts, please try again later' },
    standardHeaders: true,
    legacyHeaders: false
});

// Argon2id configuration (OWASP recommended)
const ARGON2_CONFIG = {
    type: argon2.argon2id,    // Hybrid mode: resistant to side-channel and GPU attacks
    memoryCost: 65536,         // 64 MB memory usage
    timeCost: 3,               // 3 iterations
    parallelism: 4,            // 4 parallel threads
    hashLength: 32             // 256-bit output
};

// Hash algorithm detection
const HashAlgorithm = {
    ARGON2: 'argon2',
    BCRYPT: 'bcrypt',
    SHA1: 'sha1',
    MD5: 'md5',
    UNKNOWN: 'unknown'
};

function detectHashAlgorithm(hash) {
    if (hash.startsWith('$argon2')) {
        return HashAlgorithm.ARGON2;
    } else if (hash.startsWith('$2a$') || hash.startsWith('$2b$')) {
        return HashAlgorithm.BCRYPT;
    } else if (hash.length === 40 && /^[a-f0-9]+$/i.test(hash)) {
        return HashAlgorithm.SHA1;
    } else if (hash.length === 32 && /^[a-f0-9]+$/i.test(hash)) {
        return HashAlgorithm.MD5;
    }
    return HashAlgorithm.UNKNOWN;
}

// Verify password against any supported algorithm
async function verifyLegacyPassword(password, hash, algorithm) {
    switch (algorithm) {
        case HashAlgorithm.ARGON2:
            return await argon2.verify(hash, password);
        case HashAlgorithm.BCRYPT:
            return await bcrypt.compare(password, hash);
        case HashAlgorithm.SHA1:
            // LEGACY: Only for migration, never for new passwords
            const sha1Hash = crypto.createHash('sha1').update(password).digest('hex');
            return crypto.timingSafeEqual(
                Buffer.from(sha1Hash, 'hex'),
                Buffer.from(hash, 'hex')
            );
        case HashAlgorithm.MD5:
            // LEGACY: Only for migration, never for new passwords
            const md5Hash = crypto.createHash('md5').update(password).digest('hex');
            return crypto.timingSafeEqual(
                Buffer.from(md5Hash, 'hex'),
                Buffer.from(hash, 'hex')
            );
        default:
            return false;
    }
}

// Secure password hashing with Argon2id
async function hashPasswordSecure(password) {
    return await argon2.hash(password, ARGON2_CONFIG);
}

// Check if hash needs upgrade to Argon2
function needsRehash(hash) {
    const algorithm = detectHashAlgorithm(hash);

    // Any non-Argon2 hash needs upgrade
    if (algorithm !== HashAlgorithm.ARGON2) {
        return true;
    }

    // Check if Argon2 parameters need update
    return argon2.needsRehash(hash, ARGON2_CONFIG);
}

// Transparent hash upgrade on login
async function upgradeHashIfNeeded(userId, password, currentHash) {
    if (needsRehash(currentHash)) {
        const newHash = await hashPasswordSecure(password);

        await db.query(
            'UPDATE users SET password_hash = ?, hash_upgraded_at = NOW() WHERE id = ?',
            [newHash, userId]
        );

        securityLogger.info('Password hash upgraded', {
            userId: userId,
            oldAlgorithm: detectHashAlgorithm(currentHash),
            newAlgorithm: 'argon2id',
            timestamp: new Date().toISOString()
        });

        return newHash;
    }
    return currentHash;
}

// Password strength validation
function validatePasswordStrength(password) {
    const errors = [];

    if (password.length < 12) {
        errors.push('Password must be at least 12 characters');
    }
    if (password.length > 128) {
        errors.push('Password must not exceed 128 characters');
    }
    if (!/[a-z]/.test(password)) {
        errors.push('Password must contain lowercase letters');
    }
    if (!/[A-Z]/.test(password)) {
        errors.push('Password must contain uppercase letters');
    }
    if (!/[0-9]/.test(password)) {
        errors.push('Password must contain numbers');
    }

    return errors;
}

app.post('/api/register', authLimiter, async (req, res) => {
    try {
        const { username, password, email } = req.body;

        // Validate password strength
        const strengthErrors = validatePasswordStrength(password);
        if (strengthErrors.length > 0) {
            return res.status(400).json({ 
                message: 'Password does not meet requirements',
                errors: strengthErrors
            });
        }

        // Check for breached passwords (production: use HaveIBeenPwned API)
        const passwordSha1 = crypto.createHash('sha1')
            .update(password)
            .digest('hex')
            .toUpperCase();
        const prefix = passwordSha1.substring(0, 5);
        // In production: query https://api.pwnedpasswords.com/range/{prefix}

        // Hash with Argon2id
        const hashedPassword = await hashPasswordSecure(password);

        await db.query(
            'INSERT INTO users (username, email, password_hash, created_at) VALUES (?, ?, ?, NOW())',
            [username, email, hashedPassword]
        );

        securityLogger.info('New user registered', {
            username: username,
            hashAlgorithm: 'argon2id',
            timestamp: new Date().toISOString()
        });

        res.status(201).json({ message: 'User registered successfully' });

    } catch (error) {
        console.error('Registration error:', error.message);
        res.status(500).json({ message: 'Registration failed' });
    }
});

app.post('/api/login', authLimiter, async (req, res) => {
    try {
        const { username, password } = req.body;
        const clientIp = req.ip;

        const user = await db.query(
            'SELECT id, username, password_hash, failed_attempts, locked_until FROM users WHERE username = ?',
            [username]
        );

        // Constant-time response for non-existent users
        if (!user) {
            await argon2.hash('dummy-password', ARGON2_CONFIG);
            securityLogger.warn('Login attempt for non-existent user', {
                attemptedUsername: username,
                clientIp: clientIp,
                timestamp: new Date().toISOString()
            });
            return res.status(401).json({ message: 'Invalid credentials' });
        }

        // Check account lockout
        if (user.locked_until && new Date(user.locked_until) > new Date()) {
            securityLogger.warn('Login attempt on locked account', {
                userId: user.id,
                clientIp: clientIp,
                lockedUntil: user.locked_until
            });
            return res.status(423).json({ 
                message: 'Account temporarily locked',
                retryAfter: user.locked_until
            });
        }

        // Detect hash algorithm and verify
        const algorithm = detectHashAlgorithm(user.password_hash);
        const isValid = await verifyLegacyPassword(password, user.password_hash, algorithm);

        if (!isValid) {
            // Increment failed attempts
            const newFailedAttempts = (user.failed_attempts || 0) + 1;
            let lockUntil = null;

            if (newFailedAttempts >= 5) {
                // Lock account for 15 minutes after 5 failures
                lockUntil = new Date(Date.now() + 15 * 60 * 1000);
            }

            await db.query(
                'UPDATE users SET failed_attempts = ?, locked_until = ? WHERE id = ?',
                [newFailedAttempts, lockUntil, user.id]
            );

            securityLogger.warn('Failed login attempt', {
                userId: user.id,
                clientIp: clientIp,
                failedAttempts: newFailedAttempts,
                accountLocked: !!lockUntil,
                timestamp: new Date().toISOString()
            });

            return res.status(401).json({ message: 'Invalid credentials' });
        }

        // Successful login - upgrade hash if needed
        await upgradeHashIfNeeded(user.id, password, user.password_hash);

        // Reset failed attempts
        await db.query(
            'UPDATE users SET failed_attempts = 0, locked_until = NULL, last_login = NOW() WHERE id = ?',
            [user.id]
        );

        securityLogger.info('Successful login', {
            userId: user.id,
            clientIp: clientIp,
            hashAlgorithm: algorithm,
            timestamp: new Date().toISOString()
        });

        // Generate session/JWT token here
        res.json({ 
            message: 'Login successful',
            userId: user.id
        });

    } catch (error) {
        console.error('Login error:', error.message);
        res.status(500).json({ message: 'Login failed' });
    }
});

// Monitoring endpoint for hash migration progress
app.get('/api/admin/hash-migration-status', async (req, res) => {
    const stats = await db.query(`
        SELECT 
            COUNT(*) as total_users,
            SUM(CASE WHEN password_hash LIKE '$argon2%' THEN 1 ELSE 0 END) as argon2_count,
            SUM(CASE WHEN password_hash LIKE '$2%' THEN 1 ELSE 0 END) as bcrypt_count,
            SUM(CASE WHEN LENGTH(password_hash) = 40 THEN 1 ELSE 0 END) as sha1_count,
            SUM(CASE WHEN LENGTH(password_hash) = 32 THEN 1 ELSE 0 END) as md5_count
        FROM users
    `);

    res.json(stats);
});

module.exports = app;
```

**Defense in Depth Layers**:

1. **Algorithm Selection (Argon2id)**:
```javascript
// Argon2id combines:
// - Argon2i: Resistant to side-channel attacks
// - Argon2d: Resistant to GPU/ASIC attacks
const config = {
    type: argon2.argon2id,  // Hybrid mode
    memoryCost: 65536,      // Forces 64MB RAM per hash
    timeCost: 3,            // Multiple iterations
    parallelism: 4          // Thread count
};
```

2. **Transparent Hash Migration**:
```javascript
// On every successful login, check and upgrade weak hashes
async function upgradeHashIfNeeded(userId, password, currentHash) {
    if (needsRehash(currentHash)) {
        const newHash = await hashPasswordSecure(password);
        await db.query('UPDATE users SET password_hash = ? WHERE id = ?', 
                       [newHash, userId]);
    }
}
```

3. **Account Lockout Protection**:
```javascript
// Progressive lockout after failed attempts
if (newFailedAttempts >= 5) {
    lockUntil = new Date(Date.now() + 15 * 60 * 1000);
    // Alert security team for investigation
}
```

**Additional Protections**:
- **Memory-hard hashing**: Argon2's 64MB memory requirement makes GPU attacks impractical (GPUs have limited memory per core)
- **Breached password checking**: Integration with HaveIBeenPwned API prevents use of known compromised passwords
- **Comprehensive audit logging**: Every authentication event is logged for forensic analysis
- **Rate limiting**: Prevents online brute force attacks at the network level
- **Migration monitoring**: Track progress of hash upgrades across user base
- **Maximum password length**: Prevents DoS via extremely long passwords (Argon2 handles this, but 128 char limit is reasonable)

MD5 and SHA1 are **critically insecure** for password hashing. These algorithms were designed for speed, which makes them trivially crackable with modern hardware. A single GPU can compute billions of MD5 hashes per second, allowing attackers to crack most passwords in seconds.

**VULNERABLE CODE**:

```java
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.nio.charset.StandardCharsets;
import java.util.Base64;

public class InsecurePasswordHasher {

    // VULNERABLE: MD5 is cryptographically broken
    public static String hashPasswordMD5(String password) 
            throws NoSuchAlgorithmException {
        MessageDigest md = MessageDigest.getInstance("MD5");
        byte[] hashBytes = md.digest(password.getBytes(StandardCharsets.UTF_8));
        return Base64.getEncoder().encodeToString(hashBytes);
    }

    // VULNERABLE: SHA1 is also broken for password hashing
    public static String hashPasswordSHA1(String password) 
            throws NoSuchAlgorithmException {
        MessageDigest md = MessageDigest.getInstance("SHA-1");
        byte[] hashBytes = md.digest(password.getBytes(StandardCharsets.UTF_8));
        return Base64.getEncoder().encodeToString(hashBytes);
    }

    public static boolean verifyPassword(String password, String storedHash) 
            throws NoSuchAlgorithmException {
        String computedHash = hashPasswordMD5(password);
        return computedHash.equals(storedHash);
    }
}
```

**Attack Using Hashcat**:
```bash
# MD5 cracking - 50 billion hashes/second on RTX 4090
hashcat -m 0 -a 3 hashes.txt ?a?a?a?a?a?a?a?a

# SHA1 cracking - 17 billion hashes/second
hashcat -m 100 -a 0 hashes.txt rockyou.txt

# Rainbow table lookup - instant for common passwords
rcrack . -h 5d41402abc4b2a76b9719d911017c592
```

**Why This Is Dangerous**:
- MD5 produces collisions and can be reversed with rainbow tables in milliseconds
- SHA1 has known collision attacks (Google's SHAttered attack proved this in 2017)
- Neither algorithm includes salting, allowing precomputation attacks
- Both are designed for speed, not resistance to brute force
- A single GPU can crack 8-character passwords in under 1 hour

**SECURE VERSION**:

```java
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;

public class SecurePasswordHasher {

    // BCrypt with strength factor 12 (4096 iterations)
    // Each increment doubles computation time
    private static final int BCRYPT_STRENGTH = 12;
    private final PasswordEncoder passwordEncoder;

    public SecurePasswordHasher() {
        this.passwordEncoder = new BCryptPasswordEncoder(BCRYPT_STRENGTH);
    }

    /**
     * Hash a password using BCrypt.
     * BCrypt automatically generates a unique salt per password.
     * 
     * @param plainPassword The user's plaintext password
     * @return BCrypt hash including algorithm, cost factor, salt, and hash
     */
    public String hashPassword(String plainPassword) {
        if (plainPassword == null || plainPassword.length() < 8) {
            throw new IllegalArgumentException("Password must be at least 8 characters");
        }
        // BCrypt output format: $2a$12$salt22chars.hash31chars
        return passwordEncoder.encode(plainPassword);
    }

    /**
     * Verify a password against stored BCrypt hash.
     * Uses constant-time comparison to prevent timing attacks.
     * 
     * @param plainPassword The password to verify
     * @param storedHash The stored BCrypt hash
     * @return true if password matches
     */
    public boolean verifyPassword(String plainPassword, String storedHash) {
        if (plainPassword == null || storedHash == null) {
            return false;
        }
        return passwordEncoder.matches(plainPassword, storedHash);
    }
}
```

**Key Security Controls**:
- **BCrypt with work factor 12**: Each hash takes ~300ms to compute, making brute force infeasible (would take centuries instead of hours)
- **Automatic unique salt per password**: Prevents rainbow table attacks and ensures identical passwords have different hashes
- **Constant-time comparison**: The `matches()` method prevents timing attacks that could leak information about correct password characters

Excellent questions! For production systems, you need a migration strategy for legacy hashes and should consider Argon2id (winner of the Password Hashing Competition) which provides memory-hard protection against GPU attacks.

**PRODUCTION PATTERN**:

```java
import org.bouncycastle.crypto.generators.Argon2BytesGenerator;
import org.bouncycastle.crypto.params.Argon2Parameters;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.security.MessageDigest;
import java.security.SecureRandom;
import java.util.Base64;
import java.util.concurrent.atomic.AtomicLong;

public class ProductionPasswordService {

    private static final Logger logger = LoggerFactory.getLogger(ProductionPasswordService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    // Argon2id parameters (OWASP recommended)
    private static final int ARGON2_MEMORY = 65536;    // 64 MB
    private static final int ARGON2_ITERATIONS = 3;    // Time cost
    private static final int ARGON2_PARALLELISM = 4;   // Threads
    private static final int ARGON2_HASH_LENGTH = 32;  // 256 bits
    private static final int ARGON2_SALT_LENGTH = 16;  // 128 bits

    // Legacy BCrypt for migration
    private final BCryptPasswordEncoder bcryptEncoder = new BCryptPasswordEncoder(12);
    private final SecureRandom secureRandom = new SecureRandom();

    // Metrics for monitoring
    private final AtomicLong legacyHashMigrations = new AtomicLong(0);
    private final AtomicLong hashVerifications = new AtomicLong(0);

    /**
     * Hash password using Argon2id - the gold standard for password hashing.
     * Memory-hard to resist GPU/ASIC attacks.
     */
    public String hashPasswordArgon2(String password) {
        validatePassword(password);

        byte[] salt = new byte[ARGON2_SALT_LENGTH];
        secureRandom.nextBytes(salt);

        Argon2Parameters params = new Argon2Parameters.Builder(Argon2Parameters.ARGON2_id)
            .withMemoryAsKB(ARGON2_MEMORY)
            .withIterations(ARGON2_ITERATIONS)
            .withParallelism(ARGON2_PARALLELISM)
            .withSalt(salt)
            .build();

        Argon2BytesGenerator generator = new Argon2BytesGenerator();
        generator.init(params);

        byte[] hash = new byte[ARGON2_HASH_LENGTH];
        generator.generateBytes(password.toCharArray(), hash);

        // Format: $argon2id$v=19$m=65536,t=3,p=4$salt$hash
        String encodedSalt = Base64.getEncoder().withoutPadding().encodeToString(salt);
        String encodedHash = Base64.getEncoder().withoutPadding().encodeToString(hash);

        return String.format("$argon2id$v=19$m=%d,t=%d,p=%d$%s$%s",
            ARGON2_MEMORY, ARGON2_ITERATIONS, ARGON2_PARALLELISM,
            encodedSalt, encodedHash);
    }

    /**
     * Universal password verification with automatic migration.
     * Supports: Argon2id, BCrypt, and legacy MD5 (migrates on successful auth)
     */
    public PasswordVerificationResult verifyAndMigrate(
            String userId, String plainPassword, String storedHash) {

        hashVerifications.incrementAndGet();

        try {
            HashType hashType = detectHashType(storedHash);
            boolean isValid = false;
            boolean needsMigration = false;

            switch (hashType) {
                case ARGON2ID:
                    isValid = verifyArgon2(plainPassword, storedHash);
                    break;

                case BCRYPT:
                    isValid = bcryptEncoder.matches(plainPassword, storedHash);
                    needsMigration = true; // Upgrade to Argon2
                    break;

                case MD5_LEGACY:
                    isValid = verifyLegacyMD5(plainPassword, storedHash);
                    needsMigration = true;
                    if (isValid) {
                        auditLogger.warn("SECURITY_ALERT: Legacy MD5 hash verified for user={}", 
                            userId);
                    }
                    break;

                case UNKNOWN:
                    logger.error("Unknown hash format for user={}", userId);
                    return new PasswordVerificationResult(false, null, false);
            }

            String newHash = null;
            if (isValid && needsMigration) {
                newHash = hashPasswordArgon2(plainPassword);
                legacyHashMigrations.incrementAndGet();
                auditLogger.info("PASSWORD_MIGRATION: user={} from={} to=ARGON2ID", 
                    userId, hashType);
            }

            return new PasswordVerificationResult(isValid, newHash, needsMigration);

        } catch (Exception e) {
            logger.error("Password verification failed for user={}", userId, e);
            return new PasswordVerificationResult(false, null, false);
        }
    }

    private boolean verifyArgon2(String password, String storedHash) {
        // Parse stored hash: $argon2id$v=19$m=65536,t=3,p=4$salt$hash
        String[] parts = storedHash.split("\\$");
        if (parts.length != 6) return false;

        String[] params = parts[3].split(",");
        int memory = Integer.parseInt(params[0].substring(2));
        int iterations = Integer.parseInt(params[1].substring(2));
        int parallelism = Integer.parseInt(params[2].substring(2));
        byte[] salt = Base64.getDecoder().decode(parts[4]);
        byte[] expectedHash = Base64.getDecoder().decode(parts[5]);

        Argon2Parameters argonParams = new Argon2Parameters.Builder(Argon2Parameters.ARGON2_id)
            .withMemoryAsKB(memory)
            .withIterations(iterations)
            .withParallelism(parallelism)
            .withSalt(salt)
            .build();

        Argon2BytesGenerator generator = new Argon2BytesGenerator();
        generator.init(argonParams);

        byte[] computedHash = new byte[expectedHash.length];
        generator.generateBytes(password.toCharArray(), computedHash);

        return MessageDigest.isEqual(computedHash, expectedHash);
    }

    private boolean verifyLegacyMD5(String password, String storedHash) {
        try {
            MessageDigest md = MessageDigest.getInstance("MD5");
            byte[] hashBytes = md.digest(password.getBytes("UTF-8"));
            String computed = Base64.getEncoder().encodeToString(hashBytes);
            return MessageDigest.isEqual(
                computed.getBytes(), storedHash.getBytes());
        } catch (Exception e) {
            return false;
        }
    }

    private HashType detectHashType(String hash) {
        if (hash.startsWith("$argon2id$")) return HashType.ARGON2ID;
        if (hash.startsWith("$2a$") || hash.startsWith("$2b$")) return HashType.BCRYPT;
        if (hash.length() == 24 && hash.matches("[A-Za-z0-9+/=]+")) return HashType.MD5_LEGACY;
        return HashType.UNKNOWN;
    }

    private void validatePassword(String password) {
        if (password == null || password.length() < 12) {
            throw new IllegalArgumentException("Password must be at least 12 characters");
        }
        if (password.length() > 128) {
            throw new IllegalArgumentException("Password exceeds maximum length");
        }
    }

    public long getLegacyMigrationCount() {
        return legacyHashMigrations.get();
    }

    private enum HashType {
        ARGON2ID, BCRYPT, MD5_LEGACY, UNKNOWN
    }

    public static class PasswordVerificationResult {
