		db:            db,
		logger:        logger,
		useArgon2:     true,
		minLength:     12,
		maxLength:     128,
		requireUpper:  true,
		requireLower:  true,
		requireDigit:  true,
		requireSymbol: true,
	}
}

// ValidatePasswordStrength enforces password policy
func (ps *PasswordService) ValidatePasswordStrength(password string) error {
	if len(password) < ps.minLength {
		return fmt.Errorf("password must be at least %d characters", ps.minLength)
	}
	if len(password) > ps.maxLength {
		return fmt.Errorf("password must not exceed %d characters", ps.maxLength)
	}

	var hasUpper, hasLower, hasDigit, hasSymbol bool
	for _, char := range password {
		switch {
		case unicode.IsUpper(char):
			hasUpper = true
		case unicode.IsLower(char):
			hasLower = true
		case unicode.IsDigit(char):
			hasDigit = true
		case unicode.IsPunct(char) || unicode.IsSymbol(char):
			hasSymbol = true
		}
	}

	if ps.requireUpper && !hasUpper {
		return errors.New("password must contain uppercase letter")
	}
	if ps.requireLower && !hasLower {
		return errors.New("password must contain lowercase letter")
	}
	if ps.requireDigit && !hasDigit {
		return errors.New("password must contain digit")
	}
	if ps.requireSymbol && !hasSymbol {
		return errors.New("password must contain special character")
	}

	// Check against common passwords (simplified - use haveibeenpwned API in production)
	commonPasswords := regexp.MustCompile(`(?i)(password|123456|qwerty|admin)`)
	if commonPasswords.MatchString(password) {
		return errors.New("password is too common")
	}

	return nil
}

// HashPassword uses Argon2id (preferred) or bcrypt (fallback)
func (ps *PasswordService) HashPassword(password string) (*HashedPassword, error) {
	if ps.useArgon2 {
		return ps.hashArgon2id(password)
	}
	return ps.hashBcrypt(password)
}

func (ps *PasswordService) hashArgon2id(password string) (*HashedPassword, error) {
	// Generate cryptographically secure random salt
	salt := make([]byte, saltLength)
	if _, err := rand.Read(salt); err != nil {
		return nil, fmt.Errorf("failed to generate salt: %w", err)
	}

	// Argon2id is the recommended variant (resistant to side-channel and GPU attacks)
	hash := argon2.IDKey(
		[]byte(password),
		salt,
		argon2Time,
		argon2Memory,
		argon2Threads,
		argon2KeyLen,
	)

	return &HashedPassword{
		Algorithm: "argon2id",
		Hash:      base64.StdEncoding.EncodeToString(hash),
		Salt:      base64.StdEncoding.EncodeToString(salt),
		Params:    fmt.Sprintf("t=%d,m=%d,p=%d", argon2Time, argon2Memory, argon2Threads),
	}, nil
}

func (ps *PasswordService) hashBcrypt(password string) (*HashedPassword, error) {
	hash, err := bcrypt.GenerateFromPassword([]byte(password), bcryptCost)
	if err != nil {
		return nil, fmt.Errorf("bcrypt failed: %w", err)
	}

	return &HashedPassword{
		Algorithm: "bcrypt",
		Hash:      string(hash),
	}, nil
}

// VerifyPassword with constant-time comparison
func (ps *PasswordService) VerifyPassword(password string, stored *HashedPassword) (bool, error) {
	switch stored.Algorithm {
	case "argon2id":
		return ps.verifyArgon2id(password, stored)
	case "bcrypt":
		return ps.verifyBcrypt(password, stored)
	default:
		// Log unknown algorithm for security monitoring
		ps.logger.Printf("SECURITY: Unknown hash algorithm detected: %s", stored.Algorithm)
		return false, errors.New("unsupported algorithm")
	}
}

func (ps *PasswordService) verifyArgon2id(password string, stored *HashedPassword) (bool, error) {
	salt, err := base64.StdEncoding.DecodeString(stored.Salt)
	if err != nil {
		return false, fmt.Errorf("invalid salt: %w", err)
	}

	storedHash, err := base64.StdEncoding.DecodeString(stored.Hash)
	if err != nil {
		return false, fmt.Errorf("invalid hash: %w", err)
	}

	// Recompute hash with same parameters
	computedHash := argon2.IDKey(
		[]byte(password),
		salt,
		argon2Time,
		argon2Memory,
		argon2Threads,
		argon2KeyLen,
	)

	// CRITICAL: Use constant-time comparison to prevent timing attacks
	return subtle.ConstantTimeCompare(storedHash, computedHash) == 1, nil
}

func (ps *PasswordService) verifyBcrypt(password string, stored *HashedPassword) (bool, error) {
	err := bcrypt.CompareHashAndPassword([]byte(stored.Hash), []byte(password))
	return err == nil, nil
}

// RegisterHandler with full security controls
func (ps *PasswordService) RegisterHandler(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 10*time.Second)
	defer cancel()

	username := r.FormValue("username")
	password := r.FormValue("password")
	clientIP := r.RemoteAddr

	// Audit logging
	ps.logger.Printf("AUDIT: Registration attempt for user=%s from ip=%s", username, clientIP)

	// Validate password strength
	if err := ps.ValidatePasswordStrength(password); err != nil {
		ps.logger.Printf("AUDIT: Registration failed - weak password for user=%s", username)
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	// Hash password with secure algorithm
