	if err != nil {
		ps.logger.Printf("ERROR: Password hashing failed: %v", err)
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}

	// Serialize hash metadata
	hashJSON, err := json.Marshal(hashedPwd)
	if err != nil {
		ps.logger.Printf("ERROR: Hash serialization failed: %v", err)
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}

	// Store with transaction
	tx, err := ps.db.BeginTx(ctx, nil)
	if err != nil {
		ps.logger.Printf("ERROR: Transaction start failed: %v", err)
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}
	defer tx.Rollback()

	_, err = tx.ExecContext(ctx,
		`INSERT INTO users (username, password_hash, created_at, password_updated_at) 
		 VALUES ($1, $2, NOW(), NOW())`,
		username, string(hashJSON),
	)
	if err != nil {
		ps.logger.Printf("ERROR: User insert failed: %v", err)
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}

	if err := tx.Commit(); err != nil {
		ps.logger.Printf("ERROR: Transaction commit failed: %v", err)
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}

	ps.logger.Printf("AUDIT: User registered successfully user=%s alg=%s", username, hashedPwd.Algorithm)
	w.WriteHeader(http.StatusCreated)
	fmt.Fprintf(w, "User registered successfully")
}
