            byte[] hashBytes = new byte[4 + SaltSize + HashSize];
            BitConverter.GetBytes(Iterations).CopyTo(hashBytes, 0);
            salt.CopyTo(hashBytes, 4);
            hash.CopyTo(hashBytes, 4 + SaltSize);

            return Convert.ToBase64String(hashBytes);
        }

