```csharp
using System;
using System.Security.Cryptography;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Configuration;
using Konscious.Security.Cryptography; // Install-Package Konscious.Security.Cryptography.Argon2

namespace SecureApp.Services
{
    public interface IPasswordHasher
    {
        string HashPassword(string password);
        PasswordVerificationResult VerifyPassword(string password, string storedHash);
    }

    public enum PasswordVerificationResult
    {
        Failed,
        Success,
        SuccessRehashNeeded
    }

    public class SecurePasswordHasher : IPasswordHasher
    {
        private readonly ILogger<SecurePasswordHasher> _logger;
        private readonly IConfiguration _config;

        // Argon2id parameters (OWASP recommended)
        private const int SaltSize = 16;
        private const int HashSize = 32;
        private const int MemorySize = 65536; // 64 MB
        private const int Iterations = 4;
        private const int Parallelism = 4;
        private const string CurrentVersion = "argon2id-v1";

        public SecurePasswordHasher(ILogger<SecurePasswordHasher> logger, IConfiguration config)
        {
            _logger = logger;
            _config = config;
        }

        public string HashPassword(string password)
        {
            ValidatePasswordStrength(password);

            byte[] salt = RandomNumberGenerator.GetBytes(SaltSize);
            byte[] hash = ComputeArgon2idHash(password, salt);

            // Format: version$iterations$memory$parallelism$salt$hash
            string encodedSalt = Convert.ToBase64String(salt);
            string encodedHash = Convert.ToBase64String(hash);

            return $"{CurrentVersion}${Iterations}${MemorySize}${Parallelism}${encodedSalt}${encodedHash}";
        }

        private byte[] ComputeArgon2idHash(string password, byte[] salt)
        {
            using var argon2 = new Argon2id(Encoding.UTF8.GetBytes(password))
            {
                Salt = salt,
                DegreeOfParallelism = Parallelism,
                MemorySize = MemorySize,
                Iterations = Iterations
            };

            return argon2.GetBytes(HashSize);
        }

        public PasswordVerificationResult VerifyPassword(string password, string storedHash)
        {
            if (string.IsNullOrEmpty(storedHash))
            {
                _logger.LogWarning("Empty stored hash detected");
                return PasswordVerificationResult.Failed;
            }

            // Detect legacy hash formats and handle migration
            if (IsLegacyMd5Hash(storedHash))
            {
                return VerifyLegacyMd5(password, storedHash);
            }

            if (IsLegacySha1Hash(storedHash))
            {
                return VerifyLegacySha1(password, storedHash);
            }

            if (storedHash.StartsWith("argon2id-v1$"))
            {
                return VerifyArgon2id(password, storedHash);
            }

            _logger.LogError("Unknown hash format encountered");
            return PasswordVerificationResult.Failed;
        }

        private bool IsLegacyMd5Hash(string hash)
        {
            // MD5 produces 32 hex characters
            return Regex.IsMatch(hash, "^[a-f0-9]{32}$", RegexOptions.IgnoreCase);
        }

        private bool IsLegacySha1Hash(string hash)
        {
            // SHA1 produces 40 hex characters
            return Regex.IsMatch(hash, "^[a-f0-9]{40}$", RegexOptions.IgnoreCase);
        }

        private PasswordVerificationResult VerifyLegacyMd5(string password, string storedHash)
        {
            _logger.LogWarning("Legacy MD5 hash detected - migration required");

            using var md5 = MD5.Create();
            byte[] inputBytes = Encoding.UTF8.GetBytes(password);
            byte[] hashBytes = md5.ComputeHash(inputBytes);
            string computedHash = BitConverter.ToString(hashBytes).Replace("-", "").ToLower();

            if (CryptographicOperations.FixedTimeEquals(
                Encoding.UTF8.GetBytes(computedHash),
                Encoding.UTF8.GetBytes(storedHash.ToLower())))
            {
                // Password correct but needs re-hashing
                return PasswordVerificationResult.SuccessRehashNeeded;
            }

            return PasswordVerificationResult.Failed;
        }

        private PasswordVerificationResult VerifyLegacySha1(string password, string storedHash)
        {
            _logger.LogWarning("Legacy SHA1 hash detected - migration required");

            using var sha1 = SHA1.Create();
            byte[] inputBytes = Encoding.UTF8.GetBytes(password);
            byte[] hashBytes = sha1.ComputeHash(inputBytes);
            string computedHash = BitConverter.ToString(hashBytes).Replace("-", "").ToLower();

            if (CryptographicOperations.FixedTimeEquals(
                Encoding.UTF8.GetBytes(computedHash),
                Encoding.UTF8.GetBytes(storedHash.ToLower())))
            {
                return PasswordVerificationResult.SuccessRehashNeeded;
            }

            return PasswordVerificationResult.Failed;
        }

        private PasswordVerificationResult VerifyArgon2id(string password, string storedHash)
        {
            try
            {
                string[] parts = storedHash.Split('$');
                if (parts.Length != 6)
                {
                    return PasswordVerificationResult.Failed;
                }

                int iterations = int.Parse(parts[1]);
                int memorySize = int.Parse(parts[2]);
                int parallelism = int.Parse(parts[3]);
                byte[] salt = Convert.FromBase64String(parts[4]);
                byte[] expectedHash = Convert.FromBase64String(parts[5]);

                using var argon2 = new Argon2id(Encoding.UTF8.GetBytes(password))
                {
                    Salt = salt,
                    DegreeOfParallelism = parallelism,
                    MemorySize = memorySize,
                    Iterations = iterations
                };

                byte[] computedHash = argon2.GetBytes(expectedHash.Length);

                if (CryptographicOperations.FixedTimeEquals(computedHash, expectedHash))
                {
                    // Check if parameters need upgrading
                    if (iterations < Iterations || memorySize < MemorySize)
                    {
                        return PasswordVerificationResult.SuccessRehashNeeded;
                    }
                    return PasswordVerificationResult.Success;
                }

                return PasswordVerificationResult.Failed;
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error verifying Argon2id hash");
                return PasswordVerificationResult.Failed;
            }
        }

        private void ValidatePasswordStrength(string password)
        {
            if (string.IsNullOrEmpty(password))
                throw new ArgumentException("Password cannot be empty");

            if (password.Length < 12)
                throw new ArgumentException("Password must be at least 12 characters");

            if (password.Length > 128)
                throw new ArgumentException("Password cannot exceed 128 characters");
        }
    }

