    type: argon2.argon2id,        // Hybrid: resistant to side-channel & GPU
    memoryCost: 65536,            // 64 MB memory
    timeCost: 3,                  // 3 iterations
    parallelism: 4,               // 4 parallel threads
    hashLength: 32                // 256-bit output
};

// Hash algorithm identifiers for migration
const HASH_ALGORITHMS = {
    MD5: 'md5',
    SHA1: 'sha1',
    SHA256: 'sha256',
    BCRYPT: 'bcrypt',
    ARGON2: 'argon2'
};

// Detect hash algorithm from stored hash
function detectHashAlgorithm(storedHash) {
    if (storedHash.startsWith('$argon2')) {
        return HASH_ALGORITHMS.ARGON2;
    }
    if (storedHash.startsWith('$2a$') || storedHash.startsWith('$2b$')) {
        return HASH_ALGORITHMS.BCRYPT;
    }
    if (storedHash.length === 32) {
        return HASH_ALGORITHMS.MD5;
    }
    if (storedHash.length === 40) {
        return HASH_ALGORITHMS.SHA1;
    }
    if (storedHash.length === 64) {
        return HASH_ALGORITHMS.SHA256;
    }
    return null;
}

// SECURE: Hash password with Argon2id
