    try {
        return await argon2.hash(password, ARGON2_CONFIG);
    } catch (error) {
        securityLogger.error('Argon2 hashing failed', { error: error.message });
        throw new Error('Password hashing failed');
    }
}

// Verify password against any supported algorithm
async function verifyPassword(password, storedHash, algorithm) {
    switch (algorithm) {
        case HASH_ALGORITHMS.ARGON2:
            return await argon2.verify(storedHash, password);

        case HASH_ALGORITHMS.MD5:
            // LEGACY: Only for migration purposes
            const md5Hash = crypto.createHash('md5')
                .update(password)
                .digest('hex');
            return crypto.timingSafeEqual(
                Buffer.from(md5Hash),
                Buffer.from(storedHash)
            );

        case HASH_ALGORITHMS.SHA1:
            // LEGACY: Only for migration purposes
            const sha1Hash = crypto.createHash('sha1')
                .update(password)
                .digest('hex');
            return crypto.timingSafeEqual(
                Buffer.from(sha1Hash),
                Buffer.from(storedHash)
            );

        default:
            return false;
    }
}

