import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;

public class ProductionPasswordService {
    private static final Logger logger = Logger.getLogger(ProductionPasswordService.class.getName());
    private static final Logger securityLogger = Logger.getLogger("SECURITY_AUDIT");

    // Modern algorithm: Argon2id (winner of Password Hashing Competition)
    private final PasswordEncoder argon2Encoder = new Argon2PasswordEncoder(
        16,  // salt length
        32,  // hash length  
        1,   // parallelism
        65536, // memory in KB (64MB)
        3    // iterations
    );

    // Fallback for existing BCrypt hashes
    private final PasswordEncoder bcryptEncoder = new BCryptPasswordEncoder(12);

    // Rate limiting: 5 attempts per minute per IP
    private final ConcurrentHashMap<String, Bucket> rateLimiters = new ConcurrentHashMap<>();

    private final DataSource dataSource;

    public ProductionPasswordService(DataSource dataSource) {
        this.dataSource = dataSource;
    }

    public AuthResult authenticate(String username, String password, String clientIp) {
        // Rate limiting check
        Bucket bucket = rateLimiters.computeIfAbsent(clientIp, this::createBucket);
        if (!bucket.tryConsume(1)) {
            securityLogger.warning("Rate limit exceeded for IP: " + clientIp);
            return AuthResult.rateLimited();
        }

        try {
            UserCredentials creds = fetchCredentials(username);
            if (creds == null) {
                // Prevent user enumeration with constant-time fake verification
                argon2Encoder.matches(password, "$argon2id$v=19$m=65536,t=3,p=1$fakesalt$fakehash");
                securityLogger.info("Failed login attempt for unknown user: " + username + " from " + clientIp);
                return AuthResult.failed();
            }

            boolean valid = verifyWithMigration(password, creds);

            if (valid) {
                securityLogger.info("Successful login: " + username + " from " + clientIp);
                return AuthResult.success(creds.getUserId());
            } else {
                securityLogger.warning("Failed login attempt: " + username + " from " + clientIp);
                incrementFailedAttempts(username);
                return AuthResult.failed();
            }

        } catch (SQLException e) {
            logger.severe("Database error during authentication: " + e.getMessage());
            return AuthResult.error();
        }
    }

    private boolean verifyWithMigration(String password, UserCredentials creds) throws SQLException {
        String storedHash = creds.getPasswordHash();
        String algorithm = creds.getHashAlgorithm();
        boolean valid = false;

        switch (algorithm) {
            case "md5":
                // Legacy MD5 verification (for migration only)
                valid = verifyLegacyMd5(password, storedHash);
                if (valid) {
                    migrateToArgon2(creds.getUserId(), password);
                    securityLogger.info("Migrated user " + creds.getUserId() + " from MD5 to Argon2");
                }
                break;

            case "sha1":
                // Legacy SHA1 verification (for migration only)
                valid = verifyLegacySha1(password, storedHash);
                if (valid) {
                    migrateToArgon2(creds.getUserId(), password);
                    securityLogger.info("Migrated user " + creds.getUserId() + " from SHA1 to Argon2");
                }
                break;

            case "bcrypt":
                valid = bcryptEncoder.matches(password, storedHash);
                // Optionally migrate to Argon2
                if (valid && shouldUpgradeToBcrypt(storedHash)) {
                    migrateToArgon2(creds.getUserId(), password);
                }
                break;

            case "argon2":
            default:
                valid = argon2Encoder.matches(password, storedHash);
                break;
        }

        return valid;
    }

    private boolean verifyLegacyMd5(String password, String storedHash) {
        try {
            MessageDigest md = MessageDigest.getInstance("MD5");
            byte[] hashBytes = md.digest(password.getBytes());
            StringBuilder hexString = new StringBuilder();
            for (byte b : hashBytes) {
                hexString.append(String.format("%02x", b));
            }
            return MessageDigest.isEqual(
                hexString.toString().getBytes(), 
                storedHash.getBytes()
            );
        } catch (Exception e) {
            return false;
        }
    }

    private boolean verifyLegacySha1(String password, String storedHash) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-1");
            byte[] hashBytes = md.digest(password.getBytes());
            StringBuilder hexString = new StringBuilder();
            for (byte b : hashBytes) {
                hexString.append(String.format("%02x", b));
            }
            return MessageDigest.isEqual(
                hexString.toString().getBytes(), 
                storedHash.getBytes()
            );
        } catch (Exception e) {
            return false;
        }
    }

    private void migrateToArgon2(long userId, String plainPassword) throws SQLException {
        String newHash = argon2Encoder.encode(plainPassword);

        try (Connection conn = dataSource.getConnection();
             PreparedStatement stmt = conn.prepareStatement(
                 "UPDATE users SET password_hash = ?, hash_algorithm = ?, hash_migrated_at = NOW() WHERE id = ?")) {
            stmt.setString(1, newHash);
            stmt.setString(2, "argon2");
            stmt.setLong(3, userId);
            stmt.executeUpdate();
        }
    }

    private boolean shouldUpgradeToBcrypt(String hash) {
        // Check if BCrypt work factor is below current standard
        return hash.startsWith("$2a$10") || hash.startsWith("$2a$08");
    }

    private Bucket createBucket(String key) {
        Bandwidth limit = Bandwidth.simple(5, Duration.ofMinutes(1));
        return Bucket.builder().addLimit(limit).build();
    }

    private UserCredentials fetchCredentials(String username) throws SQLException {
        try (Connection conn = dataSource.getConnection();
             PreparedStatement stmt = conn.prepareStatement(
                 "SELECT id, password_hash, hash_algorithm, failed_attempts FROM users WHERE username = ? AND account_locked = false")) {
            stmt.setString(1, username);
            try (ResultSet rs = stmt.executeQuery()) {
                if (rs.next()) {
                    return new UserCredentials(
                        rs.getLong("id"),
                        rs.getString("password_hash"),
                        rs.getString("hash_algorithm"),
                        rs.getInt("failed_attempts")
                    );
                }
            }
        }
        return null;
    }

    private void incrementFailedAttempts(String username) throws SQLException {
        try (Connection conn = dataSource.getConnection();
             PreparedStatement stmt = conn.prepareStatement(
                 "UPDATE users SET failed_attempts = failed_attempts + 1, " +
                 "account_locked = CASE WHEN failed_attempts >= 4 THEN true ELSE false END " +
                 "WHERE username = ?")) {
            stmt.setString(1, username);
            stmt.executeUpdate();
        }
    }
}
