Argon2 is the winner of the Password Hashing Competition (2015) and is considered the gold standard for password hashing. It's memory-hard, making GPU/ASIC attacks significantly more expensive than bcrypt.

**PRODUCTION PATTERN**:

```go
package main

import (
	"crypto/rand"
	"crypto/subtle"
	"database/sql"
	"encoding/base64"
	"errors"
	"fmt"
	"log"
	"net/http"
	"strings"
	"time"
	"unicode"

	"golang.org/x/crypto/argon2"
	_ "github.com/lib/pq"
)

// Argon2id parameters (OWASP recommended)
type Argon2Params struct {
	Memory      uint32 // Memory in KiB
	Iterations  uint32 // Time cost
	Parallelism uint8  // Threads
	SaltLength  uint32 // Salt size in bytes
	KeyLength   uint32 // Derived key length
}

// Production-recommended parameters
var DefaultParams = Argon2Params{
	Memory:      64 * 1024, // 64 MiB
	Iterations:  3,         // 3 iterations
	Parallelism: 4,         // 4 threads
	SaltLength:  16,        // 128-bit salt
	KeyLength:   32,        // 256-bit key
}

// PasswordPolicy defines complexity requirements
type PasswordPolicy struct {
	MinLength        int
	MaxLength        int
	RequireUppercase bool
	RequireLowercase bool
	RequireDigit     bool
	RequireSpecial   bool
	MinUniqueChars   int
}

var DefaultPolicy = PasswordPolicy{
	MinLength:        12,
	MaxLength:        128,
	RequireUppercase: true,
	RequireLowercase: true,
	RequireDigit:     true,
	RequireSpecial:   true,
	MinUniqueChars:   8,
}

// ValidatePasswordComplexity checks password against policy
func ValidatePasswordComplexity(password string, policy PasswordPolicy) error {
	if len(password) < policy.MinLength {
		return fmt.Errorf("password must be at least %d characters", policy.MinLength)
	}
	if len(password) > policy.MaxLength {
		return fmt.Errorf("password must not exceed %d characters", policy.MaxLength)
	}

	var hasUpper, hasLower, hasDigit, hasSpecial bool
	uniqueChars := make(map[rune]bool)

	for _, char := range password {
		uniqueChars[char] = true
		switch {
		case unicode.IsUpper(char):
			hasUpper = true
		case unicode.IsLower(char):
			hasLower = true
		case unicode.IsDigit(char):
			hasDigit = true
		case unicode.IsPunct(char) || unicode.IsSymbol(char):
			hasSpecial = true
		}
	}

	if policy.RequireUppercase && !hasUpper {
		return errors.New("password must contain at least one uppercase letter")
	}
	if policy.RequireLowercase && !hasLower {
		return errors.New("password must contain at least one lowercase letter")
	}
	if policy.RequireDigit && !hasDigit {
		return errors.New("password must contain at least one digit")
	}
	if policy.RequireSpecial && !hasSpecial {
		return errors.New("password must contain at least one special character")
	}
	if len(uniqueChars) < policy.MinUniqueChars {
		return fmt.Errorf("password must contain at least %d unique characters", policy.MinUniqueChars)
	}

	return nil
}

// GenerateSecureSalt creates cryptographically random salt
func GenerateSecureSalt(length uint32) ([]byte, error) {
	salt := make([]byte, length)
	_, err := rand.Read(salt)
	if err != nil {
		return nil, fmt.Errorf("failed to generate salt: %w", err)
	}
	return salt, nil
}

// HashPasswordArgon2id creates Argon2id hash with encoded parameters
func HashPasswordArgon2id(password string, params Argon2Params) (string, error) {
	// Validate password complexity first
	if err := ValidatePasswordComplexity(password, DefaultPolicy); err != nil {
		return "", err
	}

	// Generate cryptographically secure salt
	salt, err := GenerateSecureSalt(params.SaltLength)
	if err != nil {
		return "", err
	}

	// Hash using Argon2id (hybrid of Argon2i and Argon2d)
	hash := argon2.IDKey(
		[]byte(password),
		salt,
		params.Iterations,
		params.Memory,
		params.Parallelism,
		params.KeyLength,
	)

	// Encode in PHC string format for storage
	// Format: $argon2id$v=19$m=65536,t=3,p=4$<salt>$<hash>
	encodedHash := fmt.Sprintf(
		"$argon2id$v=%d$m=%d,t=%d,p=%d$%s$%s",
		argon2.Version,
		params.Memory,
		params.Iterations,
		params.Parallelism,
		base64.RawStdEncoding.EncodeToString(salt),
		base64.RawStdEncoding.EncodeToString(hash),
	)

	return encodedHash, nil
}

// VerifyPasswordArgon2id verifies password against stored hash
func VerifyPasswordArgon2id(password, encodedHash string) (bool, error) {
	// Parse the encoded hash
	params, salt, hash, err := decodeHash(encodedHash)
	if err != nil {
		return false, err
	}

	// Recompute hash with same parameters
	computedHash := argon2.IDKey(
		[]byte(password),
		salt,
		params.Iterations,
		params.Memory,
		params.Parallelism,
		params.KeyLength,
	)

	// Constant-time comparison to prevent timing attacks
	if subtle.ConstantTimeCompare(hash, computedHash) == 1 {
		return true, nil
	}

	return false, nil
}

func decodeHash(encodedHash string) (Argon2Params, []byte, []byte, error) {
	parts := strings.Split(encodedHash, "$")
	if len(parts) != 6 {
		return Argon2Params{}, nil, nil, errors.New("invalid hash format")
	}

	if parts[1] != "argon2id" {
		return Argon2Params{}, nil, nil, errors.New("unsupported algorithm")
	}

	var version int
	_, err := fmt.Sscanf(parts[2], "v=%d", &version)
	if err != nil {
		return Argon2Params{}, nil, nil, err
	}

	var params Argon2Params
	_, err = fmt.Sscanf(parts[3], "m=%d,t=%d,p=%d",
		&params.Memory, &params.Iterations, &params.Parallelism)
	if err != nil {
		return Argon2Params{}, nil, nil, err
	}

	salt, err := base64.RawStdEncoding.DecodeString(parts[4])
	if err != nil {
		return Argon2Params{}, nil, nil, err
	}

	hash, err := base64.RawStdEncoding.DecodeString(parts[5])
	if err != nil {
		return Argon2Params{}, nil, nil, err
	}

	params.SaltLength = uint32(len(salt))
	params.KeyLength = uint32(len(hash))

	return params, salt, hash, nil
}

// SecurityLogger for audit logging
type SecurityLogger struct {
	logger *log.Logger
}

func (sl *SecurityLogger) LogAuthEvent(event, username, ip string, success bool) {
	sl.logger.Printf(
		"AUTH_EVENT: event=%s user=%s ip=%s success=%t timestamp=%s",
		event, username, ip, success, time.Now().UTC().Format(time.RFC3339),
	)
}

var securityLog = &SecurityLogger{logger: log.Default()}

// Production login handler with full security controls
func loginHandler(db *sql.DB) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		clientIP := r.RemoteAddr
		username := r.FormValue("username")

		// Rate limiting would be applied via middleware

		// Fetch stored hash
		var storedHash string
		err := db.QueryRow(
			"SELECT password_hash FROM users WHERE username = $1",
			username,
		).Scan(&storedHash)

		if err == sql.ErrNoRows {
			// Perform dummy hash to prevent timing attacks
			_, _ = HashPasswordArgon2id("dummy_password_for_timing", DefaultParams)
			securityLog.LogAuthEvent("login_failed", username, clientIP, false)
			http.Error(w, "Invalid credentials", http.StatusUnauthorized)
			return
		}
		if err != nil {
			securityLog.LogAuthEvent("login_error", username, clientIP, false)
			http.Error(w, "Authentication error", http.StatusInternalServerError)
			return
		}

		password := r.FormValue("password")
		valid, err := VerifyPasswordArgon2id(password, storedHash)
		if err != nil || !valid {
			securityLog.LogAuthEvent("login_failed", username, clientIP, false)
			http.Error(w, "Invalid credentials", http.StatusUnauthorized)
			return
		}

		// Check if rehashing is needed (parameter upgrade)
		if needsRehash(storedHash) {
			newHash, _ := HashPasswordArgon2id(password, DefaultParams)
			_, _ = db.Exec(
				"UPDATE users SET password_hash = $1 WHERE username = $2",
				newHash, username,
			)
		}

		securityLog.LogAuthEvent("login_success", username, clientIP, true)
		fmt.Fprintf(w, "Login successful")
	}
}

func needsRehash(encodedHash string) bool {
	params, _, _, err := decodeHash(encodedHash)
	if err != nil {
		return true
	}
	// Check if stored hash uses weaker parameters than current defaults
	return params.Memory < DefaultParams.Memory ||
		params.Iterations < DefaultParams.Iterations
}
