```csharp
using System;
using System.Security.Cryptography;
using Microsoft.AspNetCore.Cryptography.KeyDerivation;

namespace SecureAuth
{
    public class SecurePasswordService
    {
        // Configurable work factor (increase over time as hardware improves)
        private const int IterationCount = 350000; // OWASP 2023 recommendation
        private const int SaltSize = 128 / 8; // 128 bits
        private const int HashSize = 256 / 8; // 256 bits

        public string HashPassword(string password)
        {
            if (string.IsNullOrEmpty(password))
                throw new ArgumentException("Password cannot be null or empty");

            // Generate cryptographically secure random salt
            byte[] salt = RandomNumberGenerator.GetBytes(SaltSize);

            // Use PBKDF2 with SHA-256 (FIPS compliant, widely supported)
            byte[] hash = KeyDerivation.Pbkdf2(
                password: password,
                salt: salt,
                prf: KeyDerivationPrf.HMACSHA256,
                iterationCount: IterationCount,
                numBytesRequested: HashSize
            );

            // Combine iteration count, salt, and hash for storage
            // Format: iterations:salt:hash (all base64 encoded)
            return $"{IterationCount}:{Convert.ToBase64String(salt)}:{Convert.ToBase64String(hash)}";
        }

        public bool VerifyPassword(string password, string storedHash)
        {
            if (string.IsNullOrEmpty(password) || string.IsNullOrEmpty(storedHash))
                return false;

            try
            {
                string[] parts = storedHash.Split(':');
                if (parts.Length != 3)
                    return false;

                int iterations = int.Parse(parts[0]);
                byte[] salt = Convert.FromBase64String(parts[1]);
                byte[] originalHash = Convert.FromBase64String(parts[2]);

                // Recompute hash with same parameters
                byte[] computedHash = KeyDerivation.Pbkdf2(
                    password: password,
                    salt: salt,
                    prf: KeyDerivationPrf.HMACSHA256,
                    iterationCount: iterations,
                    numBytesRequested: originalHash.Length
                );

                // Constant-time comparison to prevent timing attacks
                return CryptographicOperations.FixedTimeEquals(originalHash, computedHash);
            }
            catch
            {
                return false;
            }
        }
    }
}
