            };

            byte[] hash = argon2.GetBytes(Argon2HashLength);

            // Format: $argon2id$v=19$m=65536,t=4,p=4$salt$hash
            string result = $"$argon2id$v=19$m={Argon2MemorySize},t={Argon2Iterations},p={Argon2Parallelism}$" +
                           $"{Convert.ToBase64String(salt)}${Convert.ToBase64String(hash)}";

            _metrics.RecordPasswordHash(HashAlgorithmType.ARGON2ID);
            return result;
        }

        /// <summary>
        /// Verify password and transparently upgrade legacy hashes
        /// </summary>
        public PasswordVerificationResult VerifyAndUpgrade(
            string password,
            string storedHash,
            string userId)
        {
            var algorithmType = DetectHashAlgorithm(storedHash);
            bool isValid = false;
            bool needsUpgrade = false;

            try
            {
                switch (algorithmType)
                {
                    case HashAlgorithmType.MD5_LEGACY:
                        isValid = VerifyMD5Legacy(password, storedHash);
                        needsUpgrade = true;
                        LogLegacyHashUsage(userId, "MD5");
                        break;

                    case HashAlgorithmType.SHA1_LEGACY:
                        isValid = VerifySHA1Legacy(password, storedHash);
                        needsUpgrade = true;
                        LogLegacyHashUsage(userId, "SHA1");
                        break;

                    case HashAlgorithmType.BCRYPT:
                        isValid = BCrypt.Net.BCrypt.Verify(password, storedHash);
                        // Check if BCrypt work factor needs upgrade
                        needsUpgrade = BCrypt.Net.BCrypt.PasswordNeedsRehash(
                            storedHash, BCryptWorkFactor);
                        break;

                    case HashAlgorithmType.ARGON2ID:
                        isValid = VerifyArgon2id(password, storedHash);
                        // Check if parameters need upgrade
                        needsUpgrade = NeedsArgon2Upgrade(storedHash);
                        break;

                    default:
                        _logger.LogError("Unknown hash algorithm for user {UserId}", userId);
                        return new PasswordVerificationResult(false, null);
                }

                string upgradedHash = null;
                if (isValid && needsUpgrade)
                {
                    upgradedHash = HashPassword(password);
                    _logger.LogInformation(
                        "Password hash upgraded for user {UserId} from {OldAlg} to Argon2id",
                        userId, algorithmType);
                    _metrics.RecordHashUpgrade(algorithmType, HashAlgorithmType.ARGON2ID);
                }

                _metrics.RecordPasswordVerification(isValid, algorithmType);
                return new PasswordVerificationResult(isValid, upgradedHash);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Password verification failed for user {UserId}", userId);
                _metrics.RecordPasswordVerificationError();
                return new PasswordVerificationResult(false, null);
            }
        }

        private HashAlgorithmType DetectHashAlgorithm(string hash)
        {
            if (hash.StartsWith("$argon2id$"))
                return HashAlgorithmType.ARGON2ID;
            if (hash.StartsWith("$2a$") || hash.StartsWith("$2b$") || hash.StartsWith("$2y$"))
                return HashAlgorithmType.BCRYPT;
            if (hash.Length == 24) // Base64 MD5 (16 bytes = 24 chars)
                return HashAlgorithmType.MD5_LEGACY;
            if (hash.Length == 28) // Base64 SHA1 (20 bytes = 28 chars)
                return HashAlgorithmType.SHA1_LEGACY;

            throw new ArgumentException("Unknown hash format");
        }

        private bool VerifyArgon2id(string password, string storedHash)
        {
            // Parse: $argon2id$v=19$m=65536,t=4,p=4$salt$hash
            var parts = storedHash.Split('$');
            if (parts.Length != 6 || parts[1] != "argon2id")
                return false;

            var parameters = ParseArgon2Parameters(parts[3]);
            byte[] salt = Convert.FromBase64String(parts[4]);
            byte[] expectedHash = Convert.FromBase64String(parts[5]);

            using var argon2 = new Argon2id(Encoding.UTF8.GetBytes(password))
            {
                Salt = salt,
                MemorySize = parameters.MemorySize,
                Iterations = parameters.Iterations,
                DegreeOfParallelism = parameters.Parallelism
            };

            byte[] computedHash = argon2.GetBytes(expectedHash.Length);
            return CryptographicOperations.FixedTimeEquals(expectedHash, computedHash);
        }

        private bool VerifyMD5Legacy(string password, string storedHash)
        {
            // DANGEROUS: Only for migration, never for new passwords
            using var md5 = MD5.Create();
            byte[] inputBytes = Encoding.UTF8.GetBytes(password);
            byte[] hashBytes = md5.ComputeHash(inputBytes);
            string computed = Convert.ToBase64String(hashBytes);
            return CryptographicOperations.FixedTimeEquals(
                Encoding.UTF8.GetBytes(computed),
                Encoding.UTF8.GetBytes(storedHash));
        }

        private bool VerifySHA1Legacy(string password, string storedHash)
        {
            // DANGEROUS: Only for migration, never for new passwords
            using var sha1 = SHA1.Create();
            byte[] inputBytes = Encoding.UTF8.GetBytes(password);
            byte[] hashBytes = sha1.ComputeHash(inputBytes);
            string computed = Convert.ToBase64String(hashBytes);
            return CryptographicOperations.FixedTimeEquals(
                Encoding.UTF8.GetBytes(computed),
                Encoding.UTF8.GetBytes(storedHash));
        }

        private void ValidatePasswordStrength(string password)
        {
            if (string.IsNullOrEmpty(password))
                throw new ArgumentException("Password cannot be empty");
            if (password.Length < 12)
                throw new ArgumentException("Password must be at least 12 characters");
            if (password.Length > 128)
                throw new ArgumentException("Password exceeds maximum length");
        }

        private void LogLegacyHashUsage(string userId, string algorithm)
        {
            _logger.LogWarning(
                "Legacy {Algorithm} hash detected for user {UserId}. " +
                "Hash will be upgraded on successful authentication.",
                algorithm, userId);
        }

        private bool NeedsArgon2Upgrade(string storedHash)
        {
            var parts = storedHash.Split('$');
            var parameters = ParseArgon2Parameters(parts[3]);
            return parameters.MemorySize < Argon2MemorySize ||
                   parameters.Iterations < Argon2Iterations;
        }

        private (int MemorySize, int Iterations, int Parallelism) ParseArgon2Parameters(string paramString)
        {
            // Parse: m=65536,t=4,p=4
            var pairs = paramString.Split(',');
            int m = 0, t = 0, p = 0;
            foreach (var pair in pairs)
            {
                var kv = pair.Split('=');
                switch (kv[0])
                {
                    case "m": m = int.Parse(kv[1]); break;
                    case "t": t = int.Parse(kv[1]); break;
                    case "p": p = int.Parse(kv[1]); break;
                }
            }
            return (m, t, p);
        }
    }

    public record PasswordVerificationResult(bool IsValid, string UpgradedHash);

    public interface ISecurityMetrics
    {
        void RecordPasswordHash(HashAlgorithmType algorithm);
        void RecordPasswordVerification(bool success, HashAlgorithmType algorithm);
        void RecordHashUpgrade(HashAlgorithmType from, HashAlgorithmType to);
        void RecordPasswordVerificationError();
    }
}
```

**Defense in Depth Layers**:

1. **Algorithm Selection** - Use Argon2id for new passwords:
```csharp
// Argon2id is memory-hard, making GPU attacks expensive
using var argon2 = new Argon2id(passwordBytes)
{
    MemorySize = 65536,  // 64 MB required per hash attempt
    Iterations = 4,       // Time cost
    DegreeOfParallelism = 4
};
```

2. **Transparent Hash Upgrade** - Migrate on successful login:
```csharp
if (isValid && needsUpgrade)
{
    upgradedHash = HashPassword(password);
    // Caller persists upgraded hash to database
    _logger.LogInformation("Hash upgraded for user {UserId}", userId);
}
```

3. **Timing Attack Prevention** - Constant-time comparison:
```csharp
// Always compare in constant time to prevent timing attacks
return CryptographicOperations.FixedTimeEquals(expectedHash, computedHash);
```

**Additional Protections**:
- **Password strength validation**: Minimum 12 characters, maximum 128 to prevent DoS
- **Comprehensive logging**: Track algorithm usage and migration progress
- **Metrics collection**: Monitor for legacy hash usage and failed verifications
- **Graceful degradation**: Support legacy hashes while actively migrating
- **Parameter versioning**: Store hash parameters to enable future upgrades
- **Rate limiting**: Implement at the authentication layer (not shown) to prevent brute force
